export const blogPath = "/assets/blog/";

export type BlogCategory =
  | "Entrepreneurship & Capital"
  | "AI & Future Technology"
  | "VR, Gaming & Metaverse"
  | "Leadership & Founder Psychology"
  | "Creative IP & Culture"
  | "Society, Economy & Life";

export type ImageAspect = "landscape" | "portrait" | "square" | "wide";

export type BlogPost = {
  id: string;
  slug: string;
  title: string;
  category: BlogCategory;
  image: string;
  images: string[];
  imageAspect?: ImageAspect;
  excerpt: string;
  content: string[];
  legacyUrl: string;
  tags: string[];
  featured?: boolean;
  alt: string;
  seoTitle: string;
  seoDescription: string;
};

const makePost = (
  id: string,
  title: string,
  category: BlogCategory,
  image: string | string[],
  excerpt: string,
  tags: string[],
  alt: string,
  featured = false,
  imageAspect: ImageAspect = "landscape"
): BlogPost => {
  const imageList = Array.isArray(image) ? image : [image];

  return {
    id,
    slug: id,
    title,
    category,
    image: `${blogPath}${imageList[0]}`,
    images: imageList.map((item) => `${blogPath}${item}`),
    imageAspect,
    excerpt,
    content: [excerpt],
    legacyUrl: "#blog-archive",
    tags,
    alt,
    featured,
    seoTitle: `${title} | Arijit Bhattacharyya Blog`,
    seoDescription: excerpt,
  };
};

